# fix_strength_v2.ps1 — Force write + force git add
# Run from: C:\Users\Admin\panda-dashboard
Write-Host "Restoring strength.js..." -ForegroundColor Cyan

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$outPath = Join-Path (Get-Location) "pages\strength.js"

# Force overwrite
[System.IO.File]::WriteAllBytes($outPath, $bytes)
Write-Host "Written: $((Get-Item $outPath).Length) bytes to $outPath" -ForegroundColor Green

# Show first few lines to confirm content
Write-Host "--- First 5 lines ---" -ForegroundColor Yellow
Get-Content $outPath | Select-Object -First 5

# Force git to see the change
git diff pages/strength.js | Select-Object -First 20

Write-Host "--- Git status ---" -ForegroundColor Yellow
git status pages/strength.js

# Force add and commit
git add -f pages/strength.js
git status pages/strength.js

$staged = git diff --cached --name-only
Write-Host "Staged files: $staged" -ForegroundColor Cyan

if ($staged -match "strength") {
    git commit -m "fix: strength canvas height 380px + clientWidth/clientHeight"
    git push
    Write-Host "✅ Pushed! Check https://panda-dashboar.vercel.app/strength" -ForegroundColor Green
} else {
    Write-Host "⚠ strength.js not staged — file may already match remote." -ForegroundColor Yellow
    Write-Host "Trying touch + force commit..." -ForegroundColor Cyan
    # Append a space comment and remove it to force a diff
    Add-Content $outPath "// v2"
    git add -f pages/strength.js
    git commit -m "fix: strength canvas height 380px + clientWidth/clientHeight (forced)"
    git push
    Write-Host "✅ Done!" -ForegroundColor Green
}